// Process mock arbitration start webhook
const crypto = require('crypto');

const webhookSecret = $env.SUPABASE_WEBHOOK_SECRET;
const signature = $headers['x-webhook-secret'];

if (signature !== webhookSecret) {
  throw new Error('Invalid webhook signature');
}

// Check if this is a new mock_arbitration_session insertion
const record = $json.body.record;
if (!record || $json.body.type !== 'INSERT' || record.table !== 'mock_arbitration_sessions') {
  return []; // Not a new mock arbitration session
}

return [{
  json: {
    session_id: record.id,
    user_id: record.user_id,
    case_type: record.case_type,
    difficulty: record.difficulty,
    started_at: record.created_at
  }
}];

