// Process arbitration completion webhook
const crypto = require('crypto');

const webhookSecret = $env.SUPABASE_WEBHOOK_SECRET;
const signature = $headers['x-webhook-secret'];

if (signature !== webhookSecret) {
  throw new Error('Invalid webhook signature');
}

// Check if this is a mock_arbitration_sessions update to completed
const record = $json.body.record;
if (!record || $json.body.type !== 'UPDATE' || record.table !== 'mock_arbitration_sessions') {
  return []; // Not an arbitration completion
}

if (record.status !== 'completed') {
  return []; // Not completed
}

return [{
  json: {
    session_id: record.id,
    user_id: record.user_id,
    final_score: record.final_score,
    performance_feedback: record.performance_feedback,
    completed_at: record.updated_at
  }
}];

